// Static input
let arr = [1, 2, 2, 3, 4, 4, 4, 5, 5];

// Array to store unique elements
let unique = [];

// Loop through array
for (let i = 0; i < arr.length; i++) {
    // Add element if it's the first or different from previous
    if (i === 0 || arr[i] !== arr[i - 1]) {
        unique.push(arr[i]);
    }
}

// Print result
console.log(unique);
